--
-- Name: add_item_to_container(uuid, character varying, integer); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.add_item_to_container(p_container_id uuid, p_item_instance_id character varying, p_position integer DEFAULT NULL::integer) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_max_position integer;
BEGIN
    IF p_position IS NULL THEN
        SELECT COALESCE(MAX("position"), -1) + 1
        INTO v_max_position
        FROM container_contents
        WHERE container_id = p_container_id;
    ELSE
        v_max_position := p_position;
    END IF;

    INSERT INTO container_contents (container_id, item_instance_id, "position")
    VALUES (p_container_id, p_item_instance_id, v_max_position)
    ON CONFLICT (container_id, item_instance_id)
    DO UPDATE SET "position" = v_max_position, updated_at = NOW();
END;
$$;


--
-- Name: add_player_effect(uuid, character varying, character varying, integer, integer, integer, character varying, character varying); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.add_player_effect(p_player_id uuid, p_effect_type character varying, p_category character varying, p_duration integer, p_applied_at_tick integer, p_intensity integer DEFAULT 1, p_source character varying DEFAULT NULL::character varying, p_visibility_level character varying DEFAULT 'visible'::character varying) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    out_id uuid;
BEGIN
    INSERT INTO player_effects (
        player_id, effect_type, category, duration, applied_at_tick,
        intensity, source, visibility_level
    )
    VALUES (
        p_player_id, p_effect_type, p_category, p_duration, p_applied_at_tick,
        COALESCE(p_intensity, 1), p_source, COALESCE(p_visibility_level, 'visible')
    )
    RETURNING id INTO out_id;
    RETURN out_id;
END;
$$;


--
-- Name: apply_ban_sanction(uuid, text, text, uuid); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.apply_ban_sanction(p_user_id uuid, p_tier text, p_reason text, p_issued_by_player_id uuid) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_id UUID;
    v_expires_at TIMESTAMPTZ;
BEGIN
    IF p_reason IS NULL OR btrim(p_reason) = '' THEN
        RAISE EXCEPTION 'ban reason is required';
    END IF;

    IF p_tier NOT IN ('1h', '24h', '7d', 'permanent') THEN
        RAISE EXCEPTION 'invalid ban tier: %', p_tier;
    END IF;

    v_expires_at := CASE p_tier
        WHEN '1h' THEN now() + interval '1 hour'
        WHEN '24h' THEN now() + interval '24 hours'
        WHEN '7d' THEN now() + interval '7 days'
        ELSE NULL
    END;

    UPDATE account_sanctions
    SET lifted_at = now(),
        lifted_by_player_id = p_issued_by_player_id
    WHERE user_id = p_user_id
      AND sanction_type = 'ban'
      AND lifted_at IS NULL
      AND (expires_at IS NULL OR expires_at > now());

    v_id := gen_random_uuid();

    INSERT INTO account_sanctions (
        id,
        user_id,
        sanction_type,
        tier,
        reason,
        issued_by_player_id,
        issued_at,
        expires_at
    ) VALUES (
        v_id,
        p_user_id,
        'ban',
        p_tier,
        btrim(p_reason),
        p_issued_by_player_id,
        now(),
        v_expires_at
    );

    RETURN v_id;
END;
$$;


--
-- Name: apply_kick_sanction(uuid, text, uuid, integer); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.apply_kick_sanction(p_user_id uuid, p_reason text, p_issued_by_player_id uuid, p_cooldown_minutes integer) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_id UUID;
    v_expires_at TIMESTAMPTZ;
BEGIN
    IF p_reason IS NULL OR btrim(p_reason) = '' THEN
        RAISE EXCEPTION 'kick reason is required';
    END IF;

    IF p_cooldown_minutes IS NULL OR p_cooldown_minutes < 1 THEN
        RAISE EXCEPTION 'kick cooldown minutes must be at least 1';
    END IF;

    v_expires_at := now() + make_interval(mins => p_cooldown_minutes);

    UPDATE account_sanctions
    SET lifted_at = now(),
        lifted_by_player_id = p_issued_by_player_id
    WHERE user_id = p_user_id
      AND sanction_type = 'kick_cooldown'
      AND lifted_at IS NULL
      AND (expires_at IS NULL OR expires_at > now());

    v_id := gen_random_uuid();

    INSERT INTO account_sanctions (
        id,
        user_id,
        sanction_type,
        tier,
        reason,
        issued_by_player_id,
        issued_at,
        expires_at
    ) VALUES (
        v_id,
        p_user_id,
        'kick_cooldown',
        NULL,
        btrim(p_reason),
        p_issued_by_player_id,
        now(),
        v_expires_at
    );

    RETURN v_id;
END;
$$;


--
-- Name: clear_container_contents(uuid); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.clear_container_contents(p_container_id uuid) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_deleted integer;
BEGIN
    DELETE FROM container_contents
    WHERE container_id = p_container_id;

    GET DIAGNOSTICS v_deleted = ROW_COUNT;
    RETURN v_deleted;
END;
$$;


--
-- Name: clear_room_map_origins(text); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.clear_room_map_origins(p_pattern text) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE rooms
    SET map_origin_zone = FALSE
    WHERE stable_id LIKE p_pattern || '%'
      AND map_origin_zone = TRUE;
END;
$$;


--
-- Name: create_container(text, uuid, character varying, uuid, text, integer, integer, timestamp with time zone, jsonb, jsonb, character varying); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.create_container(p_source_type text, p_owner_id uuid, p_room_id character varying, p_entity_id uuid, p_lock_state text, p_capacity_slots integer, p_weight_limit integer, p_decay_at timestamp with time zone, p_allowed_roles jsonb, p_metadata_json jsonb, p_container_item_instance_id character varying) RETURNS TABLE(container_instance_id uuid, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    INSERT INTO containers (
        source_type, owner_id, room_id, entity_id, lock_state,
        capacity_slots, weight_limit, decay_at, allowed_roles,
        metadata_json, container_item_instance_id, created_at, updated_at
    ) VALUES (
        p_source_type, p_owner_id, p_room_id, p_entity_id, p_lock_state,
        p_capacity_slots, p_weight_limit, p_decay_at, p_allowed_roles,
        p_metadata_json, p_container_item_instance_id, NOW(), NOW()
    )
    RETURNING
        containers.container_instance_id,
        containers.created_at,
        containers.updated_at;
END;
$$;


--
-- Name: create_npc_definition(character varying, text, character varying, character varying, character varying, boolean, integer, real, text, text, text); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.create_npc_definition(p_name character varying, p_description text, p_npc_type character varying, p_sub_zone_id character varying, p_room_id character varying DEFAULT NULL::character varying, p_required_npc boolean DEFAULT false, p_max_population integer DEFAULT 1, p_spawn_probability real DEFAULT 1.0, p_base_stats text DEFAULT '{}'::text, p_behavior_config text DEFAULT '{}'::text, p_ai_integration_stub text DEFAULT '{}'::text) RETURNS TABLE(id bigint, name character varying, description text, npc_type character varying, sub_zone_id character varying, room_id character varying, required_npc boolean, max_population integer, spawn_probability real, base_stats text, behavior_config text, ai_integration_stub text, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    INSERT INTO npc_definitions (
        name, description, npc_type, sub_zone_id, room_id,
        required_npc, max_population, spawn_probability,
        base_stats, behavior_config, ai_integration_stub
    )
    VALUES (
        p_name, p_description, p_npc_type, p_sub_zone_id, p_room_id,
        COALESCE(p_required_npc, false), COALESCE(p_max_population, 1),
        COALESCE(p_spawn_probability, 1.0),
        COALESCE(p_base_stats, '{}'), COALESCE(p_behavior_config, '{}'),
        COALESCE(p_ai_integration_stub, '{}')
    )
    RETURNING
        npc_definitions.id,
        npc_definitions.name,
        npc_definitions.description,
        npc_definitions.npc_type,
        npc_definitions.sub_zone_id,
        npc_definitions.room_id,
        npc_definitions.required_npc,
        npc_definitions.max_population,
        npc_definitions.spawn_probability,
        npc_definitions.base_stats,
        npc_definitions.behavior_config,
        npc_definitions.ai_integration_stub,
        npc_definitions.created_at,
        npc_definitions.updated_at;
END;
$$;


--
-- Name: create_quest_instance(uuid, text, text, jsonb); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.create_quest_instance(p_player_id uuid, p_quest_id text, p_state text DEFAULT 'active'::text, p_progress jsonb DEFAULT '{}'::jsonb) RETURNS TABLE(id uuid, player_id uuid, quest_id text, state text, progress jsonb, accepted_at timestamp with time zone, completed_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    INSERT INTO quest_instances (player_id, quest_id, state, progress)
    VALUES (p_player_id, p_quest_id, p_state, COALESCE(p_progress, '{}'::jsonb))
    RETURNING
        quest_instances.id,
        quest_instances.player_id,
        quest_instances.quest_id,
        quest_instances.state,
        quest_instances.progress,
        quest_instances.accepted_at,
        quest_instances.completed_at;
END;
$$;


--
-- Name: create_spawn_rule(bigint, character varying, integer, integer, text); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.create_spawn_rule(p_npc_definition_id bigint, p_sub_zone_id character varying, p_min_population integer DEFAULT 0, p_max_population integer DEFAULT 999, p_spawn_conditions text DEFAULT '{}'::text) RETURNS TABLE(id bigint, npc_definition_id bigint, sub_zone_id character varying, min_population integer, max_population integer, spawn_conditions text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    INSERT INTO npc_spawn_rules (
        npc_definition_id, sub_zone_id, min_population, max_population, spawn_conditions
    )
    VALUES (
        p_npc_definition_id, p_sub_zone_id,
        COALESCE(p_min_population, 0), COALESCE(p_max_population, 999),
        COALESCE(p_spawn_conditions, '{}')
    )
    RETURNING
        npc_spawn_rules.id,
        npc_spawn_rules.npc_definition_id,
        npc_spawn_rules.sub_zone_id,
        npc_spawn_rules.min_population,
        npc_spawn_rules.max_population,
        npc_spawn_rules.spawn_conditions;
END;
$$;


--
-- Name: delete_container(uuid); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.delete_container(p_container_id uuid) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_deleted integer;
BEGIN
    DELETE FROM containers
    WHERE container_instance_id = p_container_id;

    GET DIAGNOSTICS v_deleted = ROW_COUNT;
    RETURN v_deleted > 0;
END;
$$;


--
-- Name: delete_npc_definition(bigint); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.delete_npc_definition(p_id bigint) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    rows_deleted integer;
BEGIN
    DELETE FROM npc_definitions WHERE npc_definitions.id = p_id;
    GET DIAGNOSTICS rows_deleted = ROW_COUNT;
    RETURN rows_deleted > 0;
END;
$$;


--
-- Name: delete_player(uuid); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.delete_player(p_id uuid) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_deleted integer;
BEGIN
    DELETE FROM player_inventories WHERE player_id = p_id;
    DELETE FROM players WHERE player_id = p_id;
    GET DIAGNOSTICS v_deleted = ROW_COUNT;
    RETURN v_deleted > 0;
END;
$$;


