--
-- Name: delete_spawn_rule(bigint); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.delete_spawn_rule(p_id bigint) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    rows_deleted integer;
BEGIN
    DELETE FROM npc_spawn_rules WHERE npc_spawn_rules.id = p_id;
    GET DIAGNOSTICS rows_deleted = ROW_COUNT;
    RETURN rows_deleted > 0;
END;
