--
-- Name: expire_effects_for_tick(integer); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.expire_effects_for_tick(p_current_tick integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    rows_deleted integer;
BEGIN
    DELETE FROM player_effects
    WHERE player_effects.applied_at_tick + player_effects.duration <= p_current_tick;
    GET DIAGNOSTICS rows_deleted = ROW_COUNT;
    RETURN rows_deleted;
END;
$$;


--
-- Name: fetch_container_items(uuid); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.fetch_container_items(p_container_id uuid) RETURNS TABLE(item_instance_id character varying, item_id character varying, item_name text, quantity integer, condition integer, metadata jsonb, "position" integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        cc.item_instance_id::character varying,
        ii.prototype_id::character varying AS item_id,
        COALESCE(ii.custom_name, ip.name)::text AS item_name,
        ii.quantity,
        ii.condition,
        ii.metadata,
        cc."position"
    FROM container_contents cc
    JOIN item_instances ii ON cc.item_instance_id = ii.item_instance_id
    JOIN item_prototypes ip ON ii.prototype_id = ip.prototype_id
    WHERE cc.container_id = p_container_id
    ORDER BY cc.position;
END;
$$;


--
-- Name: get_active_effects_for_player(uuid, integer); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.get_active_effects_for_player(p_player_id uuid, p_current_tick integer) RETURNS TABLE(id uuid, player_id uuid, effect_type character varying, category character varying, duration integer, applied_at_tick integer, intensity integer, source character varying, visibility_level character varying, created_at timestamp without time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        pe.id,
        pe.player_id,
        pe.effect_type,
        pe.category,
        pe.duration,
        pe.applied_at_tick,
        pe.intensity,
        pe.source,
        pe.visibility_level,
        pe.created_at
    FROM player_effects pe
    WHERE pe.player_id = p_player_id
      AND (pe.duration - (p_current_tick - pe.applied_at_tick)) > 0
    ORDER BY pe.applied_at_tick;
END;
$$;


--
-- Name: get_active_players_by_user_id(uuid); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.get_active_players_by_user_id(p_user_id uuid) RETURNS TABLE(player_id uuid, user_id uuid, name character varying, inventory text, status_effects text, current_room_id character varying, respawn_room_id character varying, experience_points integer, level integer, is_admin integer, profession_id bigint, created_at timestamp with time zone, last_active timestamp with time zone, stats jsonb, is_deleted boolean, deleted_at timestamp with time zone, tutorial_instance_id character varying, inventory_json text, equipped_json text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        p.player_id,
        p.user_id,
        p.name,
        p.inventory,
        p.status_effects,
        p.current_room_id,
        p.respawn_room_id,
        p.experience_points,
        p.level,
        p.is_admin,
        p.profession_id,
        p.created_at,
        p.last_active,
        p.stats,
        p.is_deleted,
        p.deleted_at,
        p.tutorial_instance_id,
        COALESCE(pi.inventory_json, '[]'),
        COALESCE(pi.equipped_json, '{}')
    FROM players p
    LEFT JOIN player_inventories pi ON pi.player_id = p.player_id
    WHERE p.user_id = p_user_id
      AND p.is_deleted = false;
END;
$$;


--
-- Name: get_active_sanction(uuid); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.get_active_sanction(p_user_id uuid) RETURNS TABLE(sanction_id uuid, user_id uuid, sanction_type text, tier text, reason text, issued_by_player_id uuid, issued_at timestamp with time zone, expires_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        s.id,
        s.user_id,
        s.sanction_type,
        s.tier,
        s.reason,
        s.issued_by_player_id,
        s.issued_at,
        s.expires_at
    FROM account_sanctions s
    WHERE s.user_id = p_user_id
      AND s.lifted_at IS NULL
      AND (s.expires_at IS NULL OR s.expires_at > now())
    ORDER BY
        CASE s.sanction_type
            WHEN 'ban' THEN 1
            WHEN 'kick_cooldown' THEN 2
            ELSE 3
        END,
        s.issued_at DESC
    LIMIT 1;
END;
$$;


