--
-- Name: get_effects_expiring_this_tick(integer); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.get_effects_expiring_this_tick(p_current_tick integer) RETURNS TABLE(player_id uuid, effect_type character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT pe.player_id, pe.effect_type
    FROM player_effects pe
    WHERE (pe.duration - (p_current_tick - pe.applied_at_tick)) <= 0;
END;
$$;


