--
-- Name: get_npc_system_statistics(); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.get_npc_system_statistics() RETURNS TABLE(total_npc_definitions bigint, npc_definitions_by_type jsonb, total_spawn_rules bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_by_type jsonb;
BEGIN
    SELECT jsonb_object_agg(npc_type, cnt)
    INTO v_by_type
    FROM (
        SELECT nd.npc_type, count(*)::bigint AS cnt
        FROM npc_definitions nd
        GROUP BY nd.npc_type
    ) t;
    RETURN QUERY
    SELECT
        (SELECT count(*)::bigint FROM npc_definitions),
        COALESCE(v_by_type, '{}'::jsonb),
        (SELECT count(*)::bigint FROM npc_spawn_rules);
END;
$$;


