--
-- Name: insert_player_skills_many(uuid, bigint[], integer[]); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.insert_player_skills_many(p_player_id uuid, p_skill_ids bigint[], p_values integer[]) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    INSERT INTO player_skills (player_id, skill_id, value)
    SELECT p_player_id, t.skill_id, LEAST(100, GREATEST(0, t.value))
    FROM unnest(p_skill_ids, p_values) AS t(skill_id, value);
END;
$$;


