-- Name: item_instance_exists(character varying); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.item_instance_exists(p_item_instance_id character varying) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN EXISTS (
        SELECT 1
        FROM item_instances
        WHERE item_instance_id = p_item_instance_id
    );
END;
$$;


--
-- Name: learn_spell(uuid, character varying, integer); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.learn_spell(p_player_id uuid, p_spell_id character varying, p_initial_mastery integer DEFAULT 0) RETURNS TABLE(id bigint, player_id uuid, spell_id character varying, mastery integer, learned_at timestamp with time zone, last_cast_at timestamp with time zone, times_cast integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    INSERT INTO player_spells (player_id, spell_id, mastery, times_cast)
    VALUES (p_player_id, p_spell_id, LEAST(100, GREATEST(0, p_initial_mastery)), 0)
    ON CONFLICT (player_id, spell_id) DO UPDATE SET mastery = player_spells.mastery
    RETURNING
        player_spells.id,
        player_spells.player_id,
        player_spells.spell_id,
        player_spells.mastery,
        player_spells.learned_at,
        player_spells.last_cast_at,
        player_spells.times_cast;
END;
$$;


--
-- Name: lift_ban_sanction(uuid, uuid); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.lift_ban_sanction(p_user_id uuid, p_lifted_by_player_id uuid) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_updated INTEGER;
BEGIN
    UPDATE account_sanctions
    SET lifted_at = now(),
        lifted_by_player_id = p_lifted_by_player_id
    WHERE user_id = p_user_id
      AND sanction_type = 'ban'
      AND lifted_at IS NULL
      AND (expires_at IS NULL OR expires_at > now());

    GET DIAGNOSTICS v_updated = ROW_COUNT;
    RETURN v_updated > 0;
END;
$$;


