--
-- Name: record_spell_cast(uuid, character varying); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.record_spell_cast(p_player_id uuid, p_spell_id character varying) RETURNS TABLE(id bigint, player_id uuid, spell_id character varying, mastery integer, learned_at timestamp with time zone, last_cast_at timestamp with time zone, times_cast integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    UPDATE player_spells
    SET times_cast = player_spells.times_cast + 1,
        last_cast_at = NOW()
    WHERE player_spells.player_id = p_player_id
      AND player_spells.spell_id = p_spell_id
    RETURNING
        player_spells.id,
        player_spells.player_id,
        player_spells.spell_id,
        player_spells.mastery,
        player_spells.learned_at,
        player_spells.last_cast_at,
        player_spells.times_cast;
END;
$$;


--
-- Name: remove_item_from_container(uuid, character varying); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.remove_item_from_container(p_container_id uuid, p_item_instance_id character varying) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
