--
-- Name: update_npc_definition(bigint, character varying, text, character varying, character varying, character varying, boolean, integer, real, text, text, text); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.update_npc_definition(p_id bigint, p_name character varying DEFAULT NULL::character varying, p_description text DEFAULT NULL::text, p_npc_type character varying DEFAULT NULL::character varying, p_sub_zone_id character varying DEFAULT NULL::character varying, p_room_id character varying DEFAULT NULL::character varying, p_required_npc boolean DEFAULT NULL::boolean, p_max_population integer DEFAULT NULL::integer, p_spawn_probability real DEFAULT NULL::real, p_base_stats text DEFAULT NULL::text, p_behavior_config text DEFAULT NULL::text, p_ai_integration_stub text DEFAULT NULL::text) RETURNS TABLE(id bigint, name character varying, description text, npc_type character varying, sub_zone_id character varying, room_id character varying, required_npc boolean, max_population integer, spawn_probability real, base_stats text, behavior_config text, ai_integration_stub text, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    UPDATE npc_definitions nd
    SET
        name = COALESCE(p_name, nd.name),
        description = COALESCE(p_description, nd.description),
        npc_type = COALESCE(p_npc_type, nd.npc_type),
        sub_zone_id = COALESCE(p_sub_zone_id, nd.sub_zone_id),
        room_id = COALESCE(p_room_id, nd.room_id),
        required_npc = COALESCE(p_required_npc, nd.required_npc),
        max_population = COALESCE(p_max_population, nd.max_population),
        spawn_probability = COALESCE(p_spawn_probability, nd.spawn_probability),
        base_stats = COALESCE(p_base_stats, nd.base_stats),
        behavior_config = COALESCE(p_behavior_config, nd.behavior_config),
        ai_integration_stub = COALESCE(p_ai_integration_stub, nd.ai_integration_stub),
        updated_at = now()
    WHERE nd.id = p_id
    RETURNING
        nd.id, nd.name, nd.description, nd.npc_type, nd.sub_zone_id, nd.room_id,
        nd.required_npc, nd.max_population, nd.spawn_probability,
        nd.base_stats, nd.behavior_config, nd.ai_integration_stub,
        nd.created_at, nd.updated_at;
END;
$$;


