CREATE FUNCTION mythos_dev.update_player_current_room(p_id uuid, p_room_id character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE players SET current_room_id = p_room_id WHERE player_id = p_id;
END;
$$;


--
-- Name: update_player_health(uuid, integer); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.update_player_health(p_player_id uuid, p_delta integer) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE players
    SET stats = jsonb_set(
        stats,
        '{current_dp}',
        (
            GREATEST(
                0,
                LEAST(
                    GREATEST(
                        COALESCE(
                            (stats->>'max_dp')::int,
                            ((COALESCE((stats->>'constitution')::int, 50)
                              + COALESCE((stats->>'size')::int, 50)) / 5)
                        ),
                        20
                    ),
                    (stats->>'current_dp')::int + p_delta
                )
            )
        )::text::jsonb
    )
    WHERE player_id = p_player_id;
END;
$$;


--
-- Name: update_player_last_active(uuid, timestamp with time zone); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.update_player_last_active(p_id uuid, p_ts timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_ts timestamp with time zone;
BEGIN
    v_ts := COALESCE(p_ts, now());
    UPDATE players SET last_active = v_ts WHERE player_id = p_id;
END;
$$;


--
-- Name: update_player_skill_value(uuid, bigint, integer); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.update_player_skill_value(p_player_id uuid, p_skill_id bigint, p_value integer) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE player_skills
    SET value = LEAST(99, GREATEST(0, p_value))
    WHERE player_skills.player_id = p_player_id
      AND player_skills.skill_id = p_skill_id;
END;
$$;


--
-- Name: update_player_spell_mastery(uuid, character varying, integer); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.update_player_spell_mastery(p_player_id uuid, p_spell_id character varying, p_new_mastery integer) RETURNS TABLE(id bigint, player_id uuid, spell_id character varying, mastery integer, learned_at timestamp with time zone, last_cast_at timestamp with time zone, times_cast integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    UPDATE player_spells
    SET mastery = LEAST(100, GREATEST(0, p_new_mastery))
    WHERE player_spells.player_id = p_player_id
      AND player_spells.spell_id = p_spell_id
    RETURNING
        player_spells.id,
        player_spells.player_id,
        player_spells.spell_id,
        player_spells.mastery,
        player_spells.learned_at,
        player_spells.last_cast_at,
        player_spells.times_cast;
END;
$$;


--
-- Name: update_player_stat_field(uuid, text[], numeric); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.update_player_stat_field(p_player_id uuid, p_path text[], p_delta numeric) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    rows_updated integer;
BEGIN
    UPDATE players
    SET stats = jsonb_set(
        COALESCE(stats, '{}'::jsonb),
        p_path,
        to_jsonb((COALESCE((stats #>> p_path)::numeric, 0) + p_delta)::numeric),
        true
    )
    WHERE player_id = p_player_id;
    GET DIAGNOSTICS rows_updated = ROW_COUNT;
    RETURN rows_updated;
END;
$$;


--
-- Name: update_player_xp(uuid, integer); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.update_player_xp(p_player_id uuid, p_delta integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    rows_updated integer;
BEGIN
    UPDATE players
    SET experience_points = experience_points + p_delta
    WHERE player_id = p_player_id;
    GET DIAGNOSTICS rows_updated = ROW_COUNT;
    RETURN rows_updated;
END;
$$;


--
-- Name: update_quest_instance_state_and_progress(uuid, text, jsonb, timestamp with time zone); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.update_quest_instance_state_and_progress(p_instance_id uuid, p_state text DEFAULT NULL::text, p_progress jsonb DEFAULT NULL::jsonb, p_completed_at timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE quest_instances
    SET
        state = COALESCE(p_state, state),
        progress = COALESCE(p_progress, progress),
        completed_at = COALESCE(p_completed_at, completed_at)
    WHERE quest_instances.id = p_instance_id;
END;
$$;


--
-- Name: upsert_item_instance(character varying, character varying, character varying, character varying, character varying, integer, integer, jsonb, character varying, jsonb, character varying, jsonb, character varying, jsonb); Type: FUNCTION; Schema: mythos_dev; Owner: -
--

CREATE FUNCTION mythos_dev.upsert_item_instance(p_item_instance_id character varying, p_prototype_id character varying, p_owner_type character varying DEFAULT 'room'::character varying, p_owner_id character varying DEFAULT NULL::character varying, p_location_context character varying DEFAULT NULL::character varying, p_quantity integer DEFAULT 1, p_condition integer DEFAULT NULL::integer, p_flags_override jsonb DEFAULT '[]'::jsonb, p_binding_state character varying DEFAULT NULL::character varying, p_attunement_state jsonb DEFAULT '{}'::jsonb, p_custom_name character varying DEFAULT NULL::character varying, p_metadata jsonb DEFAULT '{}'::jsonb, p_origin_source character varying DEFAULT NULL::character varying, p_origin_metadata jsonb DEFAULT '{}'::jsonb) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    INSERT INTO item_instances (
        item_instance_id,
        prototype_id,
        owner_type,
        owner_id,
        location_context,
        quantity,
        condition,
        flags_override,
        binding_state,
        attunement_state,
        custom_name,
        metadata,
        origin_source,
        origin_metadata,
        created_at,
        updated_at
    ) VALUES (
        p_item_instance_id,
        p_prototype_id,
        COALESCE(p_owner_type, 'room'),
        p_owner_id,
        p_location_context,
        COALESCE(p_quantity, 1),
        p_condition,
        COALESCE(p_flags_override, '[]'::jsonb),
        p_binding_state,
        COALESCE(p_attunement_state, '{}'::jsonb),
        p_custom_name,
        COALESCE(p_metadata, '{}'::jsonb),
        p_origin_source,
        COALESCE(p_origin_metadata, '{}'::jsonb),
        NOW(),
        NOW()
    )
    ON CONFLICT (item_instance_id) DO UPDATE SET
        prototype_id = EXCLUDED.prototype_id,
        owner_type = EXCLUDED.owner_type,
        owner_id = EXCLUDED.owner_id,
        location_context = EXCLUDED.location_context,
        quantity = EXCLUDED.quantity,
        condition = EXCLUDED.condition,
        flags_override = EXCLUDED.flags_override,
        binding_state = EXCLUDED.binding_state,
        attunement_state = EXCLUDED.attunement_state,
        custom_name = EXCLUDED.custom_name,
        metadata = EXCLUDED.metadata,
        origin_source = EXCLUDED.origin_source,
        origin_metadata = EXCLUDED.origin_metadata,
        updated_at = NOW();
END;
$$;


--
-- Name: upsert_player(uuid, uuid, character varying, text, text, character varying, character varying, integer, integer, integer, bigint, timestamp with time zone, timestamp with time zone, jsonb, boolean, timestamp with time zone, character varying, text, text); Type: PROCEDURE; Schema: mythos_dev; Owner: -
--

CREATE PROCEDURE mythos_dev.upsert_player(IN p_player_id uuid, IN p_user_id uuid, IN p_name character varying, IN p_inventory text, IN p_status_effects text, IN p_current_room_id character varying, IN p_respawn_room_id character varying, IN p_experience_points integer, IN p_level integer, IN p_is_admin integer, IN p_profession_id bigint, IN p_created_at timestamp with time zone, IN p_last_active timestamp with time zone, IN p_stats jsonb, IN p_is_deleted boolean, IN p_deleted_at timestamp with time zone, IN p_tutorial_instance_id character varying, IN p_inventory_json text, IN p_equipped_json text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    INSERT INTO players (
        player_id, user_id, name, inventory, status_effects,
        current_room_id, respawn_room_id, experience_points, level, is_admin,
        profession_id, created_at, last_active, stats, is_deleted, deleted_at,
        tutorial_instance_id
    ) VALUES (
        p_player_id, p_user_id, p_name, p_inventory, p_status_effects,
        p_current_room_id, p_respawn_room_id, p_experience_points, p_level, p_is_admin,
        p_profession_id, p_created_at, p_last_active, p_stats, p_is_deleted, p_deleted_at,
        p_tutorial_instance_id
    )
    ON CONFLICT (player_id) DO UPDATE SET
        user_id = EXCLUDED.user_id,
        name = EXCLUDED.name,
        inventory = EXCLUDED.inventory,
        status_effects = EXCLUDED.status_effects,
        current_room_id = EXCLUDED.current_room_id,
        respawn_room_id = EXCLUDED.respawn_room_id,
        experience_points = EXCLUDED.experience_points,
        level = EXCLUDED.level,
        is_admin = EXCLUDED.is_admin,
        profession_id = EXCLUDED.profession_id,
        last_active = EXCLUDED.last_active,
        stats = EXCLUDED.stats,
        is_deleted = EXCLUDED.is_deleted,
        deleted_at = EXCLUDED.deleted_at,
        tutorial_instance_id = EXCLUDED.tutorial_instance_id;

    INSERT INTO player_inventories (player_id, inventory_json, equipped_json)
    VALUES (p_player_id, p_inventory_json, p_equipped_json)
    ON CONFLICT (player_id) DO UPDATE SET
        inventory_json = EXCLUDED.inventory_json,
        equipped_json = EXCLUDED.equipped_json;
END;
$$;


